args.sparql:
SELECT ?winner WHERE {
  ?winner p:P1213 ?awardStatement .
  ?awardStatement ps:P1213 wd:Q1035785 .
  ?awardStatement pq:P585 [
    wikibase:timeValue "2017-01-01T00:00:00Z"^^xsd:dateTime
  ] .
}

SELECT ?winner WHERE {
  wd:Q4109853 p:P1213 ?statement .
  ?statement ps:P1213 ?winner .
  ?statement pq:P585 [ wdtn:timeValue "2017-01-01T00:00:00Z"^^xsd:dateTime ] .
}

SELECT DISTINCT ?winner WHERE {
  wd:Q4109853 p:P1213 ?awardStatement .
  ?awardStatement ps:P1213 ?winner .
  ?awardStatement pq:P585 ?dateQualifier .
  ?dateQualifier pqv:P585 "2017-01-01T00:00:00Z"^^xsd:dateTime
}

SELECT ?winner ?winnerLabel WHERE {
  wd:Q4109853 p:P1213 ?statement .
  ?statement ps:P1213 ?winner .
  ?statement pq:P585 ?dateQualifier .
  ?dateQualifier pqv:P585 ?dateValue .
  FILTER (STRSTARTS(STR(?dateValue), "2017")) .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
